module shift_register_8bit(clk, rst, load, data_in, obf_Q);
    input clk, rst, load;
    input [7:0] data_in;
    output reg [7:0] obf_Q;

    always @(posedge clk) begin
        if (rst)
            obf_Q <= 8'b00000000;
        else if (load)
            obf_Q <= data_in;
        else
            obf_Q <= {obf_Q[6:0], 1'b0};
    end
endmodule
